package middlewares

import (
	"bytes"
	"encoding/json"
	"io"
	"net/http"
	"strings"
)

func NoMongoOperators(next http.Handler) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		if r.Body == nil || r.ContentLength == 0 {
			next.ServeHTTP(w, r)
			return
		}
		raw, _ := io.ReadAll(r.Body)
		r.Body = io.NopCloser(bytes.NewReader(raw))

		var probe interface{}
		if err := json.Unmarshal(raw, &probe); err == nil {
			if containsDollarKey(probe) {
				http.Error(w, "Invalid request: operator keys not allowed", http.StatusBadRequest)
				return
			}
		}
		next.ServeHTTP(w, r)
	})
}

func containsDollarKey(v interface{}) bool {
	switch t := v.(type) {
	case map[string]interface{}:
		for k, child := range t {
			if strings.HasPrefix(k, "$") {
				return true
			}
			if containsDollarKey(child) {
				return true
			}
		}
	case []interface{}:
		for _, child := range t {
			if containsDollarKey(child) {
				return true
			}
		}
	}
	return false
}
